//
// # Lua-Service
//
// Lua-Service is a service that you can use to upload and execute a Lua script.
//
// When the service is starting, a cleanup is done first. That means
// still running scripts will be killed and it will be tested for which script
// an option is given. If something does not match, the script or option
// will be deleted.
//
// After the service is launched, ScriptOptions::autoStart will be evaluated for
// each script. If the flag is true, the script is going to be executed with a
// delay of Environment::autoStartDelay milliseconds.
//
// You can download and upload a script with Manager::getScript() and Manager::setScript().
// On upload, if the script name is already taken, the old script will be overwritten.
// Otherwise, a new script will be created.
//
// Use Manager::startScript() to execute a Lua script and Manager::terminateScript() to stop a script.
// If ScriptOptions::autoRestart is set to true, the script restarts automatically
// after it has exited.
//
// To get the output for a script use Manager::getScriptOutput(). The output
// is limited to Environment::outputBufferSize bytes and mapped to a virtual
// address. On the first query, call the method with starting address zero. After
// that use the returned address nAddr for the next request.
//
// A script can be called with arguments, see ScriptOptions and Manager::startScriptWithArgs().
package luaservice

import (
	"context"

	"github.com/arminguenther/xeruspower-go/v40410/idl"
)

// A structure that describes the state of a script.
//
// When a script is uploaded the new execState is STAT_NEW, exitType and
// exitStatus are not valid.
//
// When the execState is changed to STAT_TERMINATED, exitType and exitStatus
// will be set.
type ScriptState struct {
	ExecState  ScriptStateExecState // execution state of the script
	ExitType   ScriptStateExitType  // type of exit status
	ExitStatus int32                // exit code or signal
}

// Execution state of a script
type ScriptStateExecState int

const (
	STAT_NEW        ScriptStateExecState = iota // the script never ran (after uploading or system (re)start)
	STAT_RUNNING                                // script is running
	STAT_TERMINATED                             // script is terminated
	STAT_RESTARTING                             // script is terminated and restarts after the Environment::restartInterval
)

// Describes the type of exitStatus
type ScriptStateExitType int

const (
	EXIT_CODE ScriptStateExitType = iota // exitStatus is an exit code
	SIGNAL                               // exitStatus is a signal
)

// Script options
type ScriptOptions struct {
	DefaultArgs map[string]string // default arguments passed to the Lua script
	AutoStart   bool              // starts a script after system booting
	AutoRestart bool              // restarts a script after termination or crash
}

// Environment represents two kinds of information:
//   - limit (l)
//   - current status (cs)
//
// A limit of zero means no limit. The unit of size
// is byte. The unit of time is millisecond.
type Environment struct {
	MaxScriptMemoryGrowth int32 // maximum virtual memory growth per script (l)
	MaxAmountOfScripts    int32 // number of scripts that can be stored (l)
	AmountOfScripts       int32 // number of scripts that are stored (cs)
	MaxScriptSize         int32 // maximum size of a script file (l)
	MaxAllScriptSize      int32 // maximum size of all script files (l)
	AllScriptSize         int32 // size of all script files (cs)
	OutputBufferSize      int32 // output buffer size per script (l)
	RestartInterval       int32 // minimum delay to next (re)start (cs)
	AutoStartDelay        int32 // minimum delay to auto-start a script
}

// Error codes
const (
	NO_ERROR                         int32 = 0  // no error
	ERR_INVALID_NAME                 int32 = 1  // script name is invalid
	ERR_NO_SUCH_SCRIPT               int32 = 2  // script name not found
	ERR_MAX_SCRIPT_NUMBERS_EXCEEDED  int32 = 3  // maximum amount of stored script files is reached
	ERR_MAX_SCRIPT_SIZE_EXCEEDED     int32 = 4  // maximum size of a script file is reached
	ERR_MAX_ALL_SCRIPT_SIZE_EXCEEDED int32 = 5  // maximum size of all script files is reached
	ERR_NOT_TERMINATED               int32 = 6  // script is not terminated
	ERR_NOT_RUNNING                  int32 = 7  // script is not running
	ERR_INVALID_ADDR                 int32 = 8  // address parameter is wrong
	ERR_TOO_MANY_ARGUMENTS           int32 = 10 // too many arguments
	ERR_ARGUMENT_NOT_VALID           int32 = 11 // the argument has one or more invalid characters
)

// There is a single manager instance.
type Manager interface {
	idl.Object

	// Upload a script to instance
	//
	// If there is a script with the same name the new script will replace
	// the existing script (script must be in STAT_NEW or STAT_TERMINATED).
	//
	//	@param name    The name of the script file
	//	@param script  The script file packed in a string
	//	@param options The options for the script
	//
	//	@return NO_ERROR                           if OK
	//	@return ERR_INVALID_NAME                   if script name is invalid
	//	@return ERR_MAX_SCRIPT_SIZE_EXCEEDED       if the size of the new script is greater than the maximum file size
	//	@return ERR_MAX_ALL_SCRIPT_SIZE_EXCEEDED   if maximum size of all script files is reached
	//	@return ERR_MAX_SCRIPT_NUMBERS_EXCEEDED    if maximum amount of script files is reached
	//	@return ERR_NOT_TERMINATED                 if trying to replace a running script
	SetScript(ctx context.Context, name string, script string, options ScriptOptions) (int32, error)

	// To download a script file.
	//
	//	@param name The name of an existing script
	//
	//	@return NO_ERROR             if OK
	//	@return ERR_INVALID_NAME     if script name is invalid
	//	@return ERR_NO_SUCH_SCRIPT   if there is no script with the name
	GetScript(ctx context.Context, name string) (ret int32, script string, err error)

	// Returns all script names in a string vector.
	//
	// If there are no scripts the vector is empty.
	//
	//	@return A vector with all script names.
	GetScriptNames(ctx context.Context) ([]string, error)

	// Deletes a script.
	//
	//	@param name The name of the script
	//
	//	@return NO_ERROR             if OK
	//	@return ERR_INVALID_NAME     if script name is invalid
	//	@return ERR_NO_SUCH_SCRIPT   if there is no script with the name
	//	@return ERR_NOT_TERMINATED   if trying to delete a running script
	DeleteScript(ctx context.Context, name string) (int32, error)

	// Sets new options for a script.
	//
	//	@param name    The name of the script
	//	@param options The new options
	//
	//	@return NO_ERROR                      if OK
	//	@return ERR_INVALID_NAME              if script name is invalid
	//	@return ERR_NO_SUCH_SCRIPT            if there is no script with the name
	//	@return ERR_TOO_MANY_ARGUMENTS        if the size of the map is to big
	//	@return ERR_ARGUMENT_NOT_VALID        if a string in the arguments is not valid
	SetScriptOptions(ctx context.Context, name string, options ScriptOptions) (int32, error)

	// Returns the options for a script.
	//
	//	@param name    The name of the script
	//	@param options The options of the script
	//
	//	@return NO_ERROR             if OK
	//	@return ERR_INVALID_NAME     if script name is invalid
	//	@return ERR_NO_SUCH_SCRIPT   if there is no script with the name
	GetScriptOptions(ctx context.Context, name string) (ret int32, options ScriptOptions, err error)

	// To query the environment information.
	//
	//	@return the environment information
	GetEnvironment(ctx context.Context) (Environment, error)

	// To get output from a script as a string
	//
	// The output is stored in a string buffer with a defined size. The buffer is addressable with an
	// (virtual) address. The address will be increased every time the buffer gets filled.
	//
	// To get the output for the first time just call with address zero.
	// Use the returned nAddr in following calls.
	//
	// If iAddr is negative the last n bytes will be returned, e.g. -9 returns the last 9 characters.
	// If iAddr is zero the whole available buffer will be returned.
	// If iAddr is positive the returned buffer starts at this address.
	// If iAddr is equal to nAddr there is no data available.
	// If iAddr and oAddr are not equal there was data lost (exception: first call with zero).
	//
	//	@param name  The name of the script
	//	@param iAddr The virtual start address where the returned output should begin
	//	@param oAddr The virtual address from where the string starts
	//	@param nAddr The virtual address for the next query
	//	@param more  A boolean which indicates if there is more data available
	//
	//	@return NO_ERROR                      if OK
	//	@return ERR_INVALID_NAME              if file name is invalid
	//	@return ERR_NO_SUCH_SCRIPT            if there is no script with the name
	//	@return ERR_INVALID_ADDR              if iAddr is negative and its absolute value is greater than the limit
	GetScriptOutput(ctx context.Context, name string, iAddr int64) (ret int32, oAddr int64, nAddr int64, oString string, more bool, err error)

	// Clear the output buffer of a script.
	//
	//	@param name The name of the script
	//
	//	@return NO_ERROR                      if OK
	//	@return ERR_INVALID_NAME              if file name is invalid
	//	@return ERR_NO_SUCH_SCRIPT            if there is no script with the name
	ClearScriptOutput(ctx context.Context, name string) (int32, error)

	// Start a script
	//
	//	@return NO_ERROR             if OK
	//	@return ERR_INVALID_NAME     if file name is invalid
	//	@return ERR_NO_SUCH_SCRIPT   if there is no script with the name
	//	@return ERR_NOT_TERMINATED   if the script is running or restarting
	StartScript(ctx context.Context, name string) (int32, error)

	// Start a script with arguments
	//
	// The method starts a Lua script. You can add arguments depending on the Lua script.
	// The arguments will override the default arguments. All arguments are stored in a global table
	// called ARGS in Lua.
	//
	//	@return NO_ERROR                      if OK
	//	@return ERR_INVALID_NAME              if file name is invalid
	//	@return ERR_NO_SUCH_SCRIPT            if there is no script with the name
	//	@return ERR_NOT_TERMINATED            if the script is running or restarting
	//	@return ERR_TOO_MANY_ARGUMENTS        if the size of the map is to big
	//	@return ERR_ARGUMENT_NOT_VALID        if a string in the arguments is not valid
	StartScriptWithArgs(ctx context.Context, name string, arguments map[string]string) (int32, error)

	// Stop a script
	//
	// This method stops a running or restarting script. After terminating, ScriptOptions::autoRestart will
	// not be evaluated.
	//
	//	@return NO_ERROR             if OK
	//	@return ERR_INVALID_NAME     if file name is invalid
	//	@return ERR_NO_SUCH_SCRIPT   if there is no script with the name
	//	@return ERR_NOT_RUNNING      if the script is not running or restarting
	TerminateScript(ctx context.Context, name string) (int32, error)

	// Returns the state for a single script.
	//
	//	@param name  The script name
	//	@param state The state of the script
	//
	//	@return NO_ERROR             if OK
	//	@return ERR_INVALID_NAME     if file name is invalid
	//	@return ERR_NO_SUCH_SCRIPT   if there is no script with the name
	GetScriptState(ctx context.Context, name string) (ret int32, state ScriptState, err error)

	// Returns the state for all scripts. If the map is empty then there are no scripts on the machine.
	//
	//	@return A map with names as keys and states as values for all available scripts.
	GetScriptStates(ctx context.Context) (map[string]ScriptState, error)
}
